namespace AssembleMonitor.Models;

/// <summary>
/// PLC MW 영역 데이터 모델
/// </summary>
public class PlcMemory
{
    // 물리 입력 (MW0100~0109, 10 WORD) — PC READ
    public ushort[] InputWords { get; } = new ushort[10];

    // 물리 출력 (MW0200~0209, 10 WORD) — PC WRITE
    public ushort[] OutputWords { get; } = new ushort[10];

    // 서보 명령 비트 (MW0300~0301, 2 WORD) — PC WRITE
    public ushort[] ServoCmdWords { get; } = new ushort[2];

    // 서보 파라미터 (MW0310~0319, 10 WORD) — PC WRITE
    public ushort[] ServoParamWords { get; } = new ushort[10];

    // 서보 상태 비트 (MW0400~0401, 2 WORD) — PC READ
    public ushort[] ServoStatusWords { get; } = new ushort[2];

    // 서보 상태값 (MW0410~0419, 10 WORD) — PC READ
    public ushort[] ServoValueWords { get; } = new ushort[10];

    // 시스템/Watchdog (MW0500~0501, 2 WORD) — R/W
    public ushort[] SystemWords { get; } = new ushort[2];

    /// <summary>
    /// 특정 WORD의 특정 비트 상태 반환
    /// </summary>
    public static bool GetBit(ushort word, int bitIndex)
    {
        return (word & (1 << bitIndex)) != 0;
    }
}

