using System;
using System.Net.Sockets;
using System.Threading;
using System.Threading.Tasks;

namespace AssembleMonitor.Features.Communication;

/// <summary>
/// XGT FEnet TCP 클라이언트
/// 연결/읽기/쓰기 담당
/// </summary>
public class XgtClient : IDisposable
{
    private TcpClient? _tcp;
    private NetworkStream? _stream;
    private readonly SemaphoreSlim _lock = new(1, 1);

    public string IpAddress { get; set; } = "192.168.0.50";
    public int Port { get; set; } = 2004;
    public int TimeoutMs { get; set; } = 3000;
    public bool IsConnected => _tcp?.Connected == true;

    /// <summary>
    /// PLC 연결
    /// </summary>
    public async Task<bool> ConnectAsync()
    {
        try
        {
            Disconnect();
            _tcp = new TcpClient();
            _tcp.ReceiveTimeout = TimeoutMs;
            _tcp.SendTimeout = TimeoutMs;

            using var cts = new CancellationTokenSource(TimeoutMs);
            await _tcp.ConnectAsync(IpAddress, Port, cts.Token);
            _stream = _tcp.GetStream();
            return true;
        }
        catch
        {
            Disconnect();
            return false;
        }
    }

    /// <summary>
    /// 연결 해제
    /// </summary>
    public void Disconnect()
    {
        _stream?.Dispose();
        _tcp?.Dispose();
        _stream = null;
        _tcp = null;
    }

    /// <summary>
    /// 연속 WORD 읽기
    /// </summary>
    public async Task<ushort[]?> ReadWordsAsync(string startAddress, ushort wordCount)
    {
        if (!IsConnected || _stream == null) return null;

        await _lock.WaitAsync();
        try
        {
            var request = XgtProtocol.BuildReadRequest(startAddress, wordCount);
            await _stream.WriteAsync(request);

            var buffer = new byte[1024];
            var bytesRead = await _stream.ReadAsync(buffer);

            if (bytesRead == 0) return null;
            return XgtProtocol.ParseReadResponse(buffer, bytesRead);
        }
        catch
        {
            return null;
        }
        finally
        {
            _lock.Release();
        }
    }

    /// <summary>
    /// 연속 WORD 쓰기
    /// </summary>
    public async Task<bool> WriteWordsAsync(string startAddress, ushort[] values)
    {
        if (!IsConnected || _stream == null) return false;

        await _lock.WaitAsync();
        try
        {
            var request = XgtProtocol.BuildWriteRequest(startAddress, values);
            await _stream.WriteAsync(request);

            var buffer = new byte[256];
            var bytesRead = await _stream.ReadAsync(buffer);

            return XgtProtocol.IsResponseOk(buffer, bytesRead);
        }
        catch
        {
            return false;
        }
        finally
        {
            _lock.Release();
        }
    }

    public void Dispose()
    {
        Disconnect();
        _lock.Dispose();
    }
}

