 99→    {
100→        while (!ct.IsCancellationRequested)
101→        {
102→            var sw = System.Diagnostics.Stopwatch.StartNew();
103→            try
104→            {
105→                // 입력 읽기: MW0100~0109 (10 WORD)
106→                var inputs = await _client.ReadWordsAsync("%MW0100", 10);
107→                if (inputs != null)
108→                    UpdateWordViewModels(InputWords, inputs);
109→
110→                // 출력 읽기: MW0200~0209 (10 WORD)
111→                var outputs = await _client.ReadWordsAsync("%MW0200", 10);
112→                if (outputs != null)
113→                    UpdateWordViewModels(OutputWords, outputs);
114→
115→                // 서보 명령 읽기: MW0300~0301 (2 WORD)
116→                var servoCmds = await _client.ReadWordsAsync("%MW0300", 2);
117→
118→                // 서보 파라미터 읽기: MW0310~0319 (10 WORD)
119→                var servoParams = await _client.ReadWordsAsync("%MW0310", 10);
120→
121→                // 서보 상태 읽기: MW0400~0401 (2 WORD)
122→                var servoStatus = await _client.ReadWordsAsync("%MW0400", 2);
123→
124→                // 서보 값 읽기: MW0410~0415 (6 WORD)
125→                var servoValues = await _client.ReadWordsAsync("%MW0410", 6);
126→
127→                // 시스템 읽기: MW0500~0501 (2 WORD)
128→                var system = await _client.ReadWordsAsync("%MW0500", 2);
129→
130→                // 서보/시스템 탭 업데이트
131→                var servoSysData = new ushort[6];
132→                if (servoCmds != null) { servoSysData[0] = servoCmds[0]; servoSysData[1] = servoCmds[1]; }
133→                if (servoStatus != null) { servoSysData[2] = servoStatus[0]; servoSysData[3] = servoStatus[1]; }
134→                if (system != null) { servoSysData[4] = system[0]; servoSysData[5] = system[1]; }
135→                UpdateWordViewModels(ServoSystemWords, servoSysData);
136→
137→                // 서보 파라미터/값 (DINT) 업데이트
138→                if (servoParams is { Length: >= 6 })
139→                {
140→                    Application.Current?.Dispatcher.Invoke(() =>
141→                    {
142→                        TargetPos = (int)(servoParams[0] | (servoParams[1] << 16));
143→                        TargetVel = (int)(servoParams[2] | (servoParams[3] << 16));
144→                        JogVel = (int)(servoParams[4] | (servoParams[5] << 16));
145→                    });
146→                }
147→                if (servoValues is { Length: >= 6 })
148→                {
149→                    Application.Current?.Dispatcher.Invoke(() =>
150→                    {
151→                        ActPos = (int)(servoValues[0] | (servoValues[1] << 16));
152→                        ActVel = (int)(servoValues[2] | (servoValues[3] << 16));
153→                        ErrCode = servoValues[4];
154→                        ActPosDeg = servoValues[5];
155→                    });
156→                }
157→
158→                sw.Stop();
159→                Application.Current?.Dispatcher.Invoke(() =>
160→                {
161→                    CycleMs = (int)sw.ElapsedMilliseconds;
162→                    ConnectionStatus = $"연결됨 ({_client.IpAddress}) — {CycleMs}ms";
163→                });
164→            }
165→            catch (Exception ex)
166→            {
167→                Application.Current?.Dispatcher.Invoke(() =>
168→                {
169→                    ConnectionStatus = $"통신 에러: {ex.Message}";
170→                });
171→            }
172→
173→            // 폴링 주기: ~100ms (모니터링 용도)
174→            await Task.Delay(100, ct).ConfigureAwait(false);
175→        }
176→    }
