179→    {
180→        Application.Current?.Dispatcher.Invoke(() =>
181→        {
182→            for (int i = 0; i < Math.Min(vms.Count, data.Length); i++)
183→                vms[i].UpdateValue(data[i]);
184→        });
185→    }
