using System;
using System.Text;

namespace AssembleMonitor.Features.Communication;

/// <summary>
/// LS XGT FEnet 프로토콜 패킷 생성/파싱
/// XGT 전용 프로토콜 (포트 2004)
/// </summary>
public static class XgtProtocol
{
    // XGT 헤더 상수
    private const byte COMPANY_ID_LO = 0x4C; // 'L'
    private const byte COMPANY_ID_HI = 0x47; // 'G'
    private const ushort PLC_INFO = 0x0000;   // PLC 정보 (자동 감지)
    private const byte CPU_INFO = 0xA0;       // XGI/XGR/XEC
    private const byte SOURCE_OF_FRAME = 0x33; // PC → PLC
    private const ushort INVOKE_ID = 0x0000;
    private const ushort BCC = 0x0000;        // 미사용

    // 명령어 타입
    private const ushort CMD_READ = 0x0054;   // 연속 읽기 (RSS)
    private const ushort CMD_WRITE = 0x0058;  // 연속 쓰기 (WSS)

    // 데이터 타입
    private const ushort DATA_TYPE_WORD = 0x0014; // WORD (2바이트)

    /// <summary>
    /// 연속 WORD 읽기 요청 패킷 생성
    /// </summary>
    public static byte[] BuildReadRequest(string startAddress, ushort wordCount)
    {
        // 주소 문자열 (예: "%MW0100")
        var addrBytes = Encoding.ASCII.GetBytes(startAddress);
        var addrLen = (ushort)addrBytes.Length;

        // 데이터부 길이: 블록수(2) + 주소길이(2) + 주소(N) + 데이터개수(2)
        var dataLen = (ushort)(2 + 2 + addrLen + 2);

        return BuildPacket(CMD_READ, dataLen, writer =>
        {
            writer.Write((ushort)1);       // 블록 수: 1
            writer.Write(addrLen);         // 주소 길이
            writer.Write(addrBytes);       // 주소 문자열
            writer.Write(wordCount);       // 읽을 WORD 수
        });
    }

    /// <summary>
    /// 연속 WORD 쓰기 요청 패킷 생성
    /// </summary>
    public static byte[] BuildWriteRequest(string startAddress, ushort[] values)
    {
        var addrBytes = Encoding.ASCII.GetBytes(startAddress);
        var addrLen = (ushort)addrBytes.Length;
        var wordCount = (ushort)values.Length;

        // 데이터부 길이: 블록수(2) + 주소길이(2) + 주소(N) + 데이터개수(2) + 데이터(N*2)
        var dataLen = (ushort)(2 + 2 + addrLen + 2 + wordCount * 2);

        return BuildPacket(CMD_WRITE, dataLen, writer =>
        {
            writer.Write((ushort)1);       // 블록 수: 1
            writer.Write(addrLen);         // 주소 길이
            writer.Write(addrBytes);       // 주소 문자열
            writer.Write(wordCount);       // WORD 수
            foreach (var val in values)
                writer.Write(val);
        });
    }

    /// <summary>
    /// 응답 패킷에서 WORD 배열 추출
    /// </summary>
    public static ushort[]? ParseReadResponse(byte[] response, int length)
    {
        if (length < 32) return null; // 최소 헤더 크기

        // 헤더 20바이트 + 에러 상태 확인
        var dataLength = BitConverter.ToUInt16(response, 16);
        if (dataLength < 4) return null;

        // 에러 상태 (헤더 뒤 2바이트)
        // 위치: 20바이트 헤더 후
        var offset = 20;
        var blockCount = BitConverter.ToUInt16(response, offset);
        offset += 2;

        // 데이터 길이 (바이트 수)
        var dataBytes = BitConverter.ToUInt16(response, offset);
        offset += 2;

        var wordCount = dataBytes / 2;
        var result = new ushort[wordCount];
        for (int i = 0; i < wordCount; i++)
        {
            if (offset + 2 > length) break;
            result[i] = BitConverter.ToUInt16(response, offset);
            offset += 2;
        }

        return result;
    }

    /// <summary>
    /// 응답 패킷의 에러 여부 확인
    /// </summary>
    public static bool IsResponseOk(byte[] response, int length)
    {
        if (length < 20) return false;

        // 응답 헤더의 에러 상태 체크 (offset 18~19)
        // XGT에서는 데이터부 내 첫 2바이트가 에러 코드인 경우도 있음
        // 간단히 길이만 확인
        return length >= 24;
    }

    private static byte[] BuildPacket(ushort command, ushort dataLength,
        Action<System.IO.BinaryWriter> writeData)
    {
        using var ms = new System.IO.MemoryStream();
        using var writer = new System.IO.BinaryWriter(ms);

        // --- 헤더 (20바이트) ---
        writer.Write(COMPANY_ID_LO);        // [0] 회사 ID
        writer.Write(COMPANY_ID_HI);        // [1]
        writer.Write((byte)0x00);           // [2] 예약
        writer.Write((byte)0x00);           // [3] 예약
        writer.Write(PLC_INFO);             // [4-5] PLC 정보
        writer.Write(CPU_INFO);             // [6] CPU 정보
        writer.Write(SOURCE_OF_FRAME);      // [7] 프레임 소스
        writer.Write(INVOKE_ID);            // [8-9] 호출 ID
        writer.Write(dataLength);           // [10-11] 데이터 길이
        writer.Write((byte)0x00);           // [12] 프레임 위치 (단일 프레임)
        writer.Write((byte)0x00);           // [13] 예약
        writer.Write(BCC);                  // [14-15] BCC
        // [16-17] 명령어
        writer.Write(command);
        // [18-19] 데이터 타입
        writer.Write(DATA_TYPE_WORD);

        // --- 데이터부 ---
        writeData(writer);

        return ms.ToArray();
    }
}

