  1→using System;
  2→using System.Net.Sockets;
  3→using System.Threading;
  4→using System.Threading.Tasks;
  5→
  6→namespace AssembleMonitor.Features.Communication;
  7→
  8→/// <summary>
  9→/// XGT FEnet TCP 클라이언트
 10→/// 연결/읽기/쓰기 담당
 11→/// </summary>
 12→public class XgtClient : IDisposable
 13→{
 14→    private TcpClient? _tcp;
 15→    private NetworkStream? _stream;
 16→    private readonly SemaphoreSlim _lock = new(1, 1);
 17→
 18→    public string IpAddress { get; set; } = "192.168.0.50";
 19→    public int Port { get; set; } = 2004;
 20→    public int TimeoutMs { get; set; } = 3000;
 21→    public bool IsConnected => _tcp?.Connected == true;
 22→
 23→    /// <summary>
 24→    /// 통신 로그 콜백 (디버깅용)
 25→    /// </summary>
 26→    public Action<string>? OnLog { get; set; }
 27→
 28→    /// <summary>
 29→    /// PLC 연결
 30→    /// </summary>
 31→    public async Task<bool> ConnectAsync()
 32→    {
 33→        try
 34→        {
 35→            Disconnect();
 36→            _tcp = new TcpClient();
 37→            _tcp.ReceiveTimeout = TimeoutMs;
 38→            _tcp.SendTimeout = TimeoutMs;
 39→
 40→            using var cts = new CancellationTokenSource(TimeoutMs);
 41→            await _tcp.ConnectAsync(IpAddress, Port, cts.Token);
 42→            _stream = _tcp.GetStream();
 43→            return true;
 44→        }
 45→        catch
 46→        {
 47→            Disconnect();
 48→            return false;
 49→        }
 50→    }
 51→
 52→    /// <summary>
 53→    /// 연결 해제
 54→    /// </summary>
 55→    public void Disconnect()
 56→    {
 57→        _stream?.Dispose();
 58→        _tcp?.Dispose();
 59→        _stream = null;
 60→        _tcp = null;
 61→    }
 62→
 63→    /// <summary>
 64→    /// 연속 WORD 읽기
 65→    /// </summary>
 66→    public async Task<ushort[]?> ReadWordsAsync(string startAddress, ushort wordCount)
 67→    {
 68→        if (!IsConnected || _stream == null) return null;
 69→
 70→        await _lock.WaitAsync();
 71→        try
 72→        {
 73→            var request = XgtProtocol.BuildReadRequest(startAddress, wordCount);
 74→            LogBytes($"TX READ {startAddress} x{wordCount}", request, request.Length);
 75→            await _stream.WriteAsync(request);
 76→
 77→            var buffer = new byte[1024];
 78→            var bytesRead = await _stream.ReadAsync(buffer);
 79→            LogBytes($"RX READ {startAddress}", buffer, bytesRead);
 80→
 81→            if (bytesRead == 0) return null;
 82→            var result = XgtProtocol.ParseReadResponse(buffer, bytesRead);
 83→            if (result != null)
 84→                LogWords($"   → 파싱 결과 {startAddress}", result);
 85→            else
 86→                OnLog?.Invoke($"   → 파싱 실패 (len={bytesRead})");
 87→            return result;
 88→        }
 89→        catch (Exception ex)
 90→        {
 91→            OnLog?.Invoke($"ERR READ {startAddress}: {ex.Message}");
 92→            return null;
 93→        }
 94→        finally
 95→        {
 96→            _lock.Release();
 97→        }
 98→    }
 99→
100→    /// <summary>
101→    /// 연속 WORD 쓰기
102→    /// </summary>
103→    public async Task<bool> WriteWordsAsync(string startAddress, ushort[] values)
104→    {
105→        if (!IsConnected || _stream == null) return false;
106→
107→        await _lock.WaitAsync();
108→        try
109→        {
110→            var request = XgtProtocol.BuildWriteRequest(startAddress, values);
111→            LogBytes($"TX WRITE {startAddress} x{values.Length}", request, request.Length);
112→            await _stream.WriteAsync(request);
113→
114→            var buffer = new byte[256];
115→            var bytesRead = await _stream.ReadAsync(buffer);
116→            LogBytes($"RX WRITE {startAddress}", buffer, bytesRead);
117→
118→            var ok = XgtProtocol.IsResponseOk(buffer, bytesRead);
119→            OnLog?.Invoke($"   → 쓰기 {(ok ? "OK" : "FAIL")}");
120→            return ok;
121→        }
122→        catch (Exception ex)
123→        {
124→            OnLog?.Invoke($"ERR WRITE {startAddress}: {ex.Message}");
125→            return false;
126→        }
127→        finally
128→        {
129→            _lock.Release();
130→        }
131→    }
132→
133→    private void LogBytes(string label, byte[] data, int length)
134→    {
135→        if (OnLog == null) return;
136→        var hex = BitConverter.ToString(data, 0, Math.Min(length, 64)).Replace("-", " ");
137→        if (length > 64) hex += $" ... ({length}B)";
138→        OnLog($"[{DateTime.Now:HH:mm:ss.fff}] {label} [{length}B]: {hex}");
139→    }
140→
141→    private void LogWords(string label, ushort[] words)
142→    {
143→        if (OnLog == null) return;
144→        var hex = string.Join(" ", Array.ConvertAll(words, w => $"{w:X4}"));
145→        OnLog($"[{DateTime.Now:HH:mm:ss.fff}] {label}: {hex}");
146→    }
147→
148→    public void Dispose()
149→    {
150→        Disconnect();
151→        _lock.Dispose();
152→    }
153→}
