using System;
using System.Net.Sockets;
using System.Threading;
using System.Threading.Tasks;

namespace AssembleMonitor.Features.Communication;

/// <summary>
/// XGT FEnet TCP 클라이언트
/// 연결/읽기/쓰기 담당
/// </summary>
public class XgtClient : IDisposable
{
    private TcpClient? _tcp;
    private NetworkStream? _stream;
    private readonly SemaphoreSlim _lock = new(1, 1);

    public string IpAddress { get; set; } = "192.168.0.50";
    public int Port { get; set; } = 2004;
    public int TimeoutMs { get; set; } = 3000;
    public bool IsConnected => _tcp?.Connected == true;

    /// <summary>
    /// 통신 로그 콜백 (디버깅용)
    /// </summary>
    public Action<string>? OnLog { get; set; }

    /// <summary>
    /// PLC 연결
    /// </summary>
    public async Task<bool> ConnectAsync()
    {
        try
        {
            Disconnect();
            _tcp = new TcpClient();
            _tcp.ReceiveTimeout = TimeoutMs;
            _tcp.SendTimeout = TimeoutMs;

            using var cts = new CancellationTokenSource(TimeoutMs);
            await _tcp.ConnectAsync(IpAddress, Port, cts.Token);
            _stream = _tcp.GetStream();
            return true;
        }
        catch
        {
            Disconnect();
            return false;
        }
    }

    /// <summary>
    /// 연결 해제
    /// </summary>
    public void Disconnect()
    {
        _stream?.Dispose();
        _tcp?.Dispose();
        _stream = null;
        _tcp = null;
    }

    /// <summary>
    /// 연속 WORD 읽기
    /// </summary>
    public async Task<ushort[]?> ReadWordsAsync(string startAddress, ushort wordCount)
    {
        if (!IsConnected || _stream == null) return null;

        await _lock.WaitAsync();
        try
        {
            var request = XgtProtocol.BuildReadRequest(startAddress, wordCount);
            LogBytes($"TX READ {startAddress} x{wordCount}", request, request.Length);
            await _stream.WriteAsync(request);

            var buffer = new byte[1024];
            var bytesRead = await _stream.ReadAsync(buffer);
            LogBytes($"RX READ {startAddress}", buffer, bytesRead);

            if (bytesRead == 0) return null;
            var result = XgtProtocol.ParseReadResponse(buffer, bytesRead);
            if (result != null)
                LogWords($"   → 파싱 결과 {startAddress}", result);
            else
                OnLog?.Invoke($"   → 파싱 실패 (len={bytesRead})");
            return result;
        }
        catch (Exception ex)
        {
            OnLog?.Invoke($"ERR READ {startAddress}: {ex.Message}");
            return null;
        }
        finally
        {
            _lock.Release();
        }
    }

    /// <summary>
    /// 연속 WORD 쓰기
    /// </summary>
    public async Task<bool> WriteWordsAsync(string startAddress, ushort[] values)
    {
        if (!IsConnected || _stream == null) return false;

        await _lock.WaitAsync();
        try
        {
            var request = XgtProtocol.BuildWriteRequest(startAddress, values);
            LogBytes($"TX WRITE {startAddress} x{values.Length}", request, request.Length);
            await _stream.WriteAsync(request);

            var buffer = new byte[256];
            var bytesRead = await _stream.ReadAsync(buffer);
            LogBytes($"RX WRITE {startAddress}", buffer, bytesRead);

            var ok = XgtProtocol.IsResponseOk(buffer, bytesRead);
            OnLog?.Invoke($"   → 쓰기 {(ok ? "OK" : "FAIL")}");
            return ok;
        }
        catch (Exception ex)
        {
            OnLog?.Invoke($"ERR WRITE {startAddress}: {ex.Message}");
            return false;
        }
        finally
        {
            _lock.Release();
        }
    }

    private void LogBytes(string label, byte[] data, int length)
    {
        if (OnLog == null) return;
        var hex = BitConverter.ToString(data, 0, Math.Min(length, 64)).Replace("-", " ");
        if (length > 64) hex += $" ... ({length}B)";
        OnLog($"[{DateTime.Now:HH:mm:ss.fff}] {label} [{length}B]: {hex}");
    }

    private void LogWords(string label, ushort[] words)
    {
        if (OnLog == null) return;
        var hex = string.Join(" ", Array.ConvertAll(words, w => $"{w:X4}"));
        OnLog($"[{DateTime.Now:HH:mm:ss.fff}] {label}: {hex}");
    }

    public void Dispose()
    {
        Disconnect();
        _lock.Dispose();
    }
}

