        try
        {
            var request = XgtProtocol.BuildWriteRequest(startAddress, values);
            LogBytes($"TX WRITE {startAddress} x{values.Length}", request, request.Length);
            await _stream.WriteAsync(request);

            var buffer = new byte[256];
            var bytesRead = await _stream.ReadAsync(buffer);
            LogBytes($"RX WRITE {startAddress}", buffer, bytesRead);

            var ok = XgtProtocol.IsResponseOk(buffer, bytesRead);
            OnLog?.Invoke($"   → 쓰기 {(ok ? "OK" : "FAIL")}");
            return ok;
        }
        catch (Exception ex)
        {
            OnLog?.Invoke($"ERR WRITE {startAddress}: {ex.Message}");
            return false;
        }
        finally
        {
            _lock.Release();
        }
    }

    private void LogBytes(string label, byte[] data, int length)
    {
        if (OnLog == null) return;
        var hex = BitConverter.ToString(data, 0, Math.Min(length, 64)).Replace("-", " ");
        if (length > 64) hex += $" ... ({length}B)";
