  1→using System;
  2→using System.IO;
  3→using System.Text;
  4→
  5→namespace AssembleMonitor.Features.Communication;
  6→
  7→/// <summary>
  8→/// LS XGT FEnet 프로토콜 패킷 생성/파싱
  9→/// XGT 전용 프로토콜 (포트 2004)
 10→///
 11→/// 헤더 구조 (22바이트):
 12→/// [0-9]   CompanyID: "LSIS-XGT\0\0"
 13→/// [10-11] Reserved
 14→/// [12-13] PLC Info
 15→/// [14]    CPU Info (0xA0 = XGI/XGR/XEC)
 16→/// [15]    Source of Frame (0x33=요청, 0x11=응답)
 17→/// [16-17] Invoke ID
 18→/// [18-19] Data Length (바이트 22 이후 길이, cmd+dtype 포함)
 19→/// [20]    Slot/Position
 20→/// [21]    BCC
 21→///
 22→/// 애플리케이션 명령 (22바이트~):
 23→/// [22-23] Command (0x0054=RSS읽기, 0x0058=WSS쓰기)
 24→/// [24-25] Data Type (0x0014=WORD)
 25→/// [26+]   데이터 프레임
 26→/// </summary>
 27→public static class XgtProtocol
 28→{
 29→    // CompanyID (10바이트)
 30→    private static readonly byte[] COMPANY_ID =
 31→        [0x4C, 0x53, 0x49, 0x53, 0x2D, 0x58, 0x47, 0x54, 0x00, 0x00]; // "LSIS-XGT\0\0"
 32→
 33→    private const byte CPU_INFO = 0xA0;        // XGI/XGR/XEC
 34→    private const byte SOURCE_REQUEST = 0x33;   // PC → PLC
 35→    private const byte SOURCE_RESPONSE = 0x11;  // PLC → PC
 36→
 37→    // 명령어
 38→    private const ushort CMD_RSS_REQ = 0x0054;  // 연속 읽기 요청
 39→    private const ushort CMD_RSS_RSP = 0x0055;  // 연속 읽기 응답
 40→    private const ushort CMD_WSS_REQ = 0x0058;  // 연속 쓰기 요청
 41→    private const ushort CMD_WSS_RSP = 0x0059;  // 연속 쓰기 응답
 42→
 43→    // 데이터 타입
 44→    private const ushort DATA_TYPE_WORD = 0x0014;
 45→
 46→    // 헤더 크기
 47→    private const int HEADER_SIZE = 22;
 48→    // 앱 명령 오프셋 (cmd + dtype)
 49→    private const int APP_CMD_SIZE = 4; // cmd(2) + dtype(2)
 50→
 51→    /// <summary>
 52→    /// 연속 WORD 읽기 요청 패킷 (RSS)
 53→    /// </summary>
 54→    public static byte[] BuildReadRequest(string startAddress, ushort wordCount)
 55→    {
 56→        var addrBytes = Encoding.ASCII.GetBytes(startAddress);
 57→        var addrLen = (ushort)addrBytes.Length;
 58→
 59→        // 데이터 프레임: 블록수(2) + 주소길이(2) + 주소(N) + 읽기개수(2)
 60→        var dataFrameLen = 2 + 2 + addrLen + 2;
 61→
 62→        return BuildPacket(CMD_RSS_REQ, dataFrameLen, writer =>
 63→        {
 64→            writer.Write((ushort)1);    // 블록 수
 65→            writer.Write(addrLen);      // 주소 문자열 길이
 66→            writer.Write(addrBytes);    // 주소 문자열
 67→            writer.Write(wordCount);    // 읽을 WORD 수
 68→        });
 69→    }
 70→
 71→    /// <summary>
 72→    /// 연속 WORD 쓰기 요청 패킷 (WSS)
 73→    /// </summary>
 74→    public static byte[] BuildWriteRequest(string startAddress, ushort[] values)
 75→    {
 76→        var addrBytes = Encoding.ASCII.GetBytes(startAddress);
 77→        var addrLen = (ushort)addrBytes.Length;
 78→        var wordCount = (ushort)values.Length;
 79→
 80→        // 데이터 프레임: 블록수(2) + 주소길이(2) + 주소(N) + WORD수(2) + 데이터(N*2)
 81→        var dataFrameLen = 2 + 2 + addrLen + 2 + wordCount * 2;
 82→
 83→        return BuildPacket(CMD_WSS_REQ, dataFrameLen, writer =>
 84→        {
 85→            writer.Write((ushort)1);    // 블록 수
 86→            writer.Write(addrLen);      // 주소 문자열 길이
 87→            writer.Write(addrBytes);    // 주소 문자열
 88→            writer.Write(wordCount);    // WORD 수
 89→            foreach (var val in values)
 90→                writer.Write(val);
 91→        });
 92→    }
 93→
 94→    /// <summary>
 95→    /// 응답 패킷 파싱 결과
 96→    /// </summary>
 97→    public record ParseResult(
 98→        bool Success,
 99→        ushort Command,
100→        ushort DataType,
101→        ushort[]? Words,
102→        string ErrorInfo);
103→
104→    /// <summary>
105→    /// 응답 패킷 파싱 (범용 — 읽기/쓰기 모두)
106→    /// </summary>
107→    public static ParseResult ParseResponse(byte[] response, int length)
108→    {
109→        // 최소 헤더(22) + cmd(2) + dtype(2) = 26바이트
110→        if (length < 26)
111→            return new(false, 0, 0, null,
112→                $"응답 너무 짧음: {length}B (최소 26B 필요)");
113→
114→        // 헤더 파싱
115→        var source = response[15];
116→        var dataLen = BitConverter.ToUInt16(response, 18);
117→        var command = BitConverter.ToUInt16(response, 22);
118→        var dataType = BitConverter.ToUInt16(response, 24);
119→
120→        // 방향 확인
121→        if (source != SOURCE_RESPONSE)
122→            return new(false, command, dataType, null,
123→                $"응답 Source=0x{source:X2} (0x11 예상)");
124→
125→        // 에러 응답 체크: 커맨드 MSB가 세트되면 NAK
126→        // XGT에서는 에러 시 별도 포맷 사용
127→        var appDataOffset = 26; // cmd(2) + dtype(2) 이후
128→        var appDataLen = length - appDataOffset;
129→
130→        if (appDataLen < 2)
131→            return new(false, command, dataType, null,
132→                $"데이터 없음: cmd=0x{command:X4}, dataLen={dataLen}, total={length}B");
133→
134→        // 읽기 응답 (0x0055)
135→        if (command == CMD_RSS_RSP)
136→            return ParseReadData(response, length, appDataOffset);
137→
138→        // 쓰기 응답 (0x0059)
139→        if (command == CMD_WSS_RSP)
140→            return ParseWriteData(response, length, appDataOffset);
141→
142→        // 알 수 없는 명령
143→        return new(false, command, dataType, null,
144→            $"미지원 응답 cmd=0x{command:X4}");
145→    }
146→
147→    private static ParseResult ParseReadData(byte[] response, int length, int offset)
148→    {
149→        // [offset+0,1] = 블록 수
150→        var blockCount = BitConverter.ToUInt16(response, offset);
151→        offset += 2;
152→
153→        if (offset + 2 > length)
154→            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
155→                $"블록 수={blockCount}, 데이터 부족 ({length}B)");
156→
157→        // [offset+0,1] = 데이터 바이트 수
158→        var dataByteCount = BitConverter.ToUInt16(response, offset);
159→        offset += 2;
160→
161→        // 에러 체크: dataByteCount가 0이거나 비정상이면
162→        if (dataByteCount == 0 || offset + dataByteCount > length)
163→        {
164→            // 에러 코드일 수 있음 — 나머지 바이트 덤프
165→            var remaining = length - offset + 2; // dataByteCount 포함
166→            var dump = BitConverter.ToString(response, offset - 2,
167→                Math.Min(remaining + 2, length - offset + 2));
168→            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
169→                $"블록={blockCount}, 데이터크기={dataByteCount}, 잔여={dump}");
170→        }
171→
172→        // WORD 배열 추출
173→        var wordCount = dataByteCount / 2;
174→        var words = new ushort[wordCount];
175→        for (int i = 0; i < wordCount; i++)
176→        {
177→            if (offset + 2 > length) break;
178→            words[i] = BitConverter.ToUInt16(response, offset);
179→            offset += 2;
180→        }
181→
182→        return new(true, CMD_RSS_RSP, DATA_TYPE_WORD, words, "OK");
183→    }
184→
185→    private static ParseResult ParseWriteData(byte[] response, int length, int offset)
186→    {
187→        // 쓰기 응답: 블록 수만 확인
188→        if (offset + 2 > length)
189→            return new(false, CMD_WSS_RSP, DATA_TYPE_WORD, null,
190→                $"쓰기 응답 데이터 부족 ({length}B)");
191→
192→        var blockCount = BitConverter.ToUInt16(response, offset);
193→        return new(blockCount > 0, CMD_WSS_RSP, DATA_TYPE_WORD, null,
194→            blockCount > 0 ? "쓰기 OK" : "쓰기 실패 (block=0)");
